(function(){const TABS_LIST_SELECTOR='.md-tabs__list';const TABS_ITEM_SELECTOR='.md-tabs__item';const TABS_LINK_SELECTOR='.md-tabs__link';const STYLE_ELEMENT_ID='navigation-overlay-styles';function getStyleElement(){let styleElement=document.getElementById(STYLE_ELEMENT_ID);if(!styleElement){styleElement=document.createElement('style');styleElement.id=STYLE_ELEMENT_ID;document.head.appendChild(styleElement);}
return styleElement;}
function initializeNavigationOverlay(){const tabsList=document.querySelector(TABS_LIST_SELECTOR);if(!tabsList||tabsList.dataset.overlayBound==='true'){return;}
const styleElement=getStyleElement();let isAnimating=false;let currentHoverItem=null;tabsList.dataset.overlayBound='true';function getTabItems(){return Array.from(tabsList.querySelectorAll(TABS_ITEM_SELECTOR));}
function updateOverlayPosition(targetItem){if(!targetItem){return;}
const rect=targetItem.getBoundingClientRect();const listRect=tabsList.getBoundingClientRect();const left=rect.left-listRect.left;const width=rect.width;styleElement.textContent=`
                .md-tabs__list::before {
                    left: ${left}px !important;
                    width: ${width}px !important;
                }
            `;}
function showOverlay(){tabsList.classList.add('show-hover-overlay');}
function hideOverlay(){tabsList.classList.remove('show-hover-overlay','animating-left','animating-right');isAnimating=false;currentHoverItem=null;}
function getItemIndex(item){return getTabItems().indexOf(item);}
function triggerMoveAnimation(fromItem,toItem){if(isAnimating||!fromItem||!toItem){return;}
const fromIndex=getItemIndex(fromItem);const toIndex=getItemIndex(toItem);tabsList.classList.remove('animating-left','animating-right');isAnimating=true;if(toIndex>fromIndex){tabsList.classList.add('animating-right');}else{tabsList.classList.add('animating-left');}
window.setTimeout(()=>{tabsList.classList.remove('animating-left','animating-right');isAnimating=false;},600);}
tabsList.addEventListener('mouseover',(event)=>{const item=event.target.closest(TABS_ITEM_SELECTOR);if(!item||!tabsList.contains(item)){return;}
const activeItem=tabsList.querySelector('.md-tabs__item--active');if(item===activeItem){hideOverlay();return;}
updateOverlayPosition(item);showOverlay();if(currentHoverItem&&currentHoverItem!==item){triggerMoveAnimation(currentHoverItem,item);}
currentHoverItem=item;});tabsList.addEventListener('mouseleave',()=>{hideOverlay();});tabsList.addEventListener('click',(event)=>{const link=event.target.closest(TABS_LINK_SELECTOR);if(!link||!tabsList.contains(link)){return;}
hideOverlay();});let resizeTimeout=null;window.addEventListener('resize',()=>{window.clearTimeout(resizeTimeout);resizeTimeout=window.setTimeout(()=>{hideOverlay();},100);});}
function subscribeToPageChanges(callback){if(typeof document$!=='undefined'&&typeof document$.subscribe==='function'){document$.subscribe(()=>{window.requestAnimationFrame(()=>{callback();});});return;}
if(document.readyState==='loading'){document.addEventListener('DOMContentLoaded',callback,{once:true});return;}
callback();}
subscribeToPageChanges(()=>{initializeNavigationOverlay();});})();